export type Difficulty = "Very Easy" | "Easy" | "Basic" | "Intermediate" | "Advanced";

export type Problem = {
  id: string;
  title: string;
  difficulty: Difficulty;
  topics: string[];
  acceptance: number;
  submissions: number;
  xpReward: number;
  source: string;
  description: string;
  constraints: string[];
  inputFormat: string;
  outputFormat: string;
  sampleCases: { input: string; output: string; explanation?: string }[];
  hiddenTestCases: { input: string; output: string }[];
  hints: string[];
  solutions: Record<string, string>;
};

export const EXPANDED_TOPICS = [
  "Arrays", "Strings", "Hash Table", "Linked List", "Stack", "Queue",
  "Trees", "Binary Search Tree", "Graphs", "Dynamic Programming",
  "Greedy", "Backtracking", "Sorting", "Searching", "Two Pointers",
  "Sliding Window", "Recursion", "Bit Manipulation", "Math", "Heap",
  "Trie", "Segment Tree", "Union Find", "Divide and Conquer",
];

const XP_MAP: Record<Difficulty, number> = {
  "Very Easy": 10,
  "Easy": 25,
  "Basic": 50,
  "Intermediate": 100,
  "Advanced": 200,
};

function p(
  id: string, title: string, difficulty: Difficulty, topics: string[],
  acceptance: number, description: string, constraints: string[],
  inputFormat: string, outputFormat: string,
  sampleCases: { input: string; output: string; explanation?: string }[],
  hints: string[]
): Problem {
  return {
    id, title, difficulty, topics, acceptance,
    submissions: Math.floor(Math.random() * 15000) + 500,
    xpReward: XP_MAP[difficulty],
    source: "SyntaxMasters",
    description, constraints, inputFormat, outputFormat, sampleCases,
    hiddenTestCases: sampleCases.map(sc => ({ input: sc.input, output: sc.output })),
    hints,
    solutions: {},
  };
}

